selector_to_html = {"a[href=\"#equation-72a0ef42-f794-4e1c-9482-1c1ed37769d6\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-72a0ef42-f794-4e1c-9482-1c1ed37769d6\">\n\\[\\begin{equation}\n \\begin{aligned}\n  t^{1-\\alpha} \\dot{x}_1 &amp;= x_2 \\quad \\Rightarrow \\quad \\dot{x}_1 = t^{\\alpha-1} x_2, \\\\\n  t^{1-\\alpha} \\dot{x}_2 &amp;= -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2 \\quad \\Rightarrow \\quad \\dot{x}_2 = t^{\\alpha-1} \\left( -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2 \\right).\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#equation-2a9701b0-2f5f-4dbb-8a7c-61628aabdfb5\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-2a9701b0-2f5f-4dbb-8a7c-61628aabdfb5\">\n\\[\\begin{equation}\n \\begin{aligned}\n  \\dot{x}_1 &amp;= \\sigma^{\\alpha-1}~t^{\\alpha-1}~ x_2, \\\\\n  \\dot{x}_2 &amp;= \\sigma^{\\alpha-1}~t^{\\alpha-1}~ \\left[ -\\alpha\\omega_n^2 \\sin(x_1) - c|x_2|x_2 - \\alpha\\eta|\\cos(x_1)|\\operatorname{sgn}(x_2) \\right],\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#pendulo-simple\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">P\u00e9ndulo simple<a class=\"headerlink\" href=\"#pendulo-simple\" title=\"Link to this heading\">#</a></h1><p>Para establecer una l\u00ednea de base, primero se define el sistema cl\u00e1sico del p\u00e9ndulo no lineal con amortiguamiento. Las ecuaciones gobernantes son:</p><p><strong>Sistema cl\u00e1sico original del p\u00e9ndulo</strong></p>", "a[href=\"#equation-19e91642-f1d1-4eab-a6df-f1801d6b5df6\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-19e91642-f1d1-4eab-a6df-f1801d6b5df6\">\n\\[\\begin{equation}\n \\begin{aligned}\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_1 &amp;= x_2, \\\\\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_2 &amp;= -\\alpha\\omega_n^2 \\sin(x_1) - c|x_2|x_2 - \\alpha\\eta|\\cos(x_1)|\\operatorname{sgn}(x_2).\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#interpretacion-fisica\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Interpretaci\u00f3n f\u00edsica<a class=\"headerlink\" href=\"#interpretacion-fisica\" title=\"Link to this heading\">#</a></h2><p>El factor de escalamiento dependiente del tiempo <span class=\"math notranslate nohighlight\">\\(t^{\\alpha-1}\\)</span> tiene implicaciones f\u00edsicas interesantes:</p>", "a[href=\"#equation-d732644b-1197-46d1-a6d7-63e507477707\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-d732644b-1197-46d1-a6d7-63e507477707\">\n\\[\\begin{equation}\n \\begin{aligned}\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_1 &amp;= x_2, \\\\\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_2 &amp;= -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2.\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#equation-12d35b03-64ea-4a54-bf00-a57ddcbaee0a\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-12d35b03-64ea-4a54-bf00-a57ddcbaee0a\">\n\\[\\begin{equation}\n \\begin{aligned}\n  \\dot{x}_1 &amp;= t^{\\alpha-1} x_2, \\\\\n  \\dot{x}_2 &amp;= t^{\\alpha-1} \\left( -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2 \\right).\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#equation-bb6b5fad-a916-4174-a7af-959cb12cdfd4\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-bb6b5fad-a916-4174-a7af-959cb12cdfd4\">\n\\[\\begin{equation}\n \\begin{aligned}\n  \\dot{x}_1 &amp;= t^{\\alpha-1} x_2, \\\\\n  \\dot{x}_2 &amp;= t^{\\alpha-1} \\left[ -\\alpha\\omega_n^2 \\sin(x_1) - c|x_2|x_2 - \\alpha\\eta|\\cos(x_1)|\\operatorname{sgn}(x_2) \\right].\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#equation-2b6e08c0-c617-432a-90b9-497bed42e5e0\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-2b6e08c0-c617-432a-90b9-497bed42e5e0\">\n\\[\\begin{equation}\n \\begin{aligned}\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_1 &amp;= x_2, \\\\\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_2 &amp;= -\\alpha\\omega_n^2 \\sin(x_1) - c|x_2|x_2 - \\alpha\\eta|\\cos(x_1)|\\operatorname{sgn}(x_2),\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#equation-13d86c8d-3d67-4201-8180-6841c876feed\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-13d86c8d-3d67-4201-8180-6841c876feed\">\n\\[\\begin{equation}\n \\begin{aligned}\n  \\dot{x}_1 &amp;= x_2, \\\\\n  \\dot{x}_2 &amp;= -\\alpha\\omega_n^2 \\sin(x_1) - c|x_2|x_2 - \\alpha\\eta|\\cos(x_1)|\\operatorname{sgn}(x_2),\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#pendulo-con-efectos-de-chorro-de-aire\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">P\u00e9ndulo con efectos de chorro de aire<a class=\"headerlink\" href=\"#pendulo-con-efectos-de-chorro-de-aire\" title=\"Link to this heading\">#</a></h2><p>La ecuaci\u00f3n cl\u00e1sica del p\u00e9ndulo con efectos de chorro de aire fue propuesta por <span id=\"id1\">Hasan <em>et al.</em> (<a class=\"reference internal\" href=\"../references.html#id3\" title=\"Hasan, M. S., Deepu, P., Kumar, K., Agrawal, A., &amp; Meena, D. K. (2023). Oscillation decay of a pendulum by an air jet. Physics Letters A, 481, 129003.\">2023</a>)</span> y est\u00e1 dada como sigue</p>", "a[href=\"#equation-5255d4f8-69ca-4797-a8aa-57aef9a211c6\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-5255d4f8-69ca-4797-a8aa-57aef9a211c6\">\n\\[\\begin{equation}\n \\begin{aligned}\n  \\dot{x}_1 &amp;= x_2, \\\\\n  \\dot{x}_2 &amp;= -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2.\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#decaimiento-de-la-oscilacion-de-un-pendulo-debido-a-un-chorro-de-aire\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Decaimiento de la oscilaci\u00f3n de un p\u00e9ndulo debido a un chorro de aire<a class=\"headerlink\" href=\"#decaimiento-de-la-oscilacion-de-un-pendulo-debido-a-un-chorro-de-aire\" title=\"Link to this heading\">#</a></h2><p>Cabe recordar que la ecuaci\u00f3n presentada por <span id=\"id3\">Hasan <em>et al.</em> (<a class=\"reference internal\" href=\"../references.html#id3\" title=\"Hasan, M. S., Deepu, P., Kumar, K., Agrawal, A., &amp; Meena, D. K. (2023). Oscillation decay of a pendulum by an air jet. Physics Letters A, 481, 129003.\">2023</a>)</span> est\u00e1 dada como sigue</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(`article.bd-article ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: false,
                placement: 'auto-start', maxWidth: 500, interactive: true, boundary: document.body, appendTo: document.body,
                onShow(instance) {MathJax.typesetPromise([instance.popper]).then(() => {var isFirefox=typeof InstallTrigger!=='undefined';if(isFirefox&&window.MathJax&&MathJax.startup&&MathJax.startup.output&&MathJax.startup.output.name==="SVG"){const svgs=instance.popper.querySelectorAll('svg');svgs.forEach(svg=>{let bbox=svg.getBBox(),x=bbox.x,y=bbox.y,width=bbox.width,height=bbox.height;svg.setAttribute('width',width);svg.setAttribute('height',height);svg.setAttribute('viewBox',`${x} ${y} ${width} ${height}`);});let rescale=0.015;svgs.forEach(svg=>{let bbox=svg.getBBox(),width=bbox.width,height=bbox.height;svg.setAttribute('width',width*rescale);svg.setAttribute('height',height*rescale);});}});},
            });
        };
    };
    console.log("tippy tips loaded!");
};
